import { observeApiError, MetricsApiStatusTypes } from '../lib/observeApiError';

describe('observeApiError', () => {
    it('calls metricObserver with "failure" when error is falsy', () => {
        const metricObserver = jest.fn();

        observeApiError(undefined, metricObserver);
        expect(metricObserver).toHaveBeenCalledWith('failure');
        expect(metricObserver).toHaveBeenCalledTimes(1);
    });

    it('calls metricObserver with "failure" when error is null', () => {
        const metricObserver = jest.fn();

        observeApiError(null, metricObserver);
        expect(metricObserver).toHaveBeenCalledWith('failure');
        expect(metricObserver).toHaveBeenCalledTimes(1);
    });

    it('calls metricObserver with "failure" when error is empty string', () => {
        const metricObserver = jest.fn();

        observeApiError('', metricObserver);
        expect(metricObserver).toHaveBeenCalledWith('failure');
        expect(metricObserver).toHaveBeenCalledTimes(1);
    });

    it('calls metricObserver with "failure" when error is 0', () => {
        const metricObserver = jest.fn();

        observeApiError(0, metricObserver);
        expect(metricObserver).toHaveBeenCalledWith('failure');
        expect(metricObserver).toHaveBeenCalledTimes(1);
    });

    it('calls metricObserver with "failure" when error is false', () => {
        const metricObserver = jest.fn();

        observeApiError(false, metricObserver);
        expect(metricObserver).toHaveBeenCalledWith('failure');
        expect(metricObserver).toHaveBeenCalledTimes(1);
    });

    it('calls metricObserver with "5xx" when error.status is 500', () => {
        const metricObserver = jest.fn();
        const error = { status: 500 };

        observeApiError(error, metricObserver);
        expect(metricObserver).toHaveBeenCalledWith('5xx');
        expect(metricObserver).toHaveBeenCalledTimes(1);
    });

    it('calls metricObserver with "5xx" when error.status is 503', () => {
        const metricObserver = jest.fn();
        const error = { status: 503 };

        observeApiError(error, metricObserver);
        expect(metricObserver).toHaveBeenCalledWith('5xx');
        expect(metricObserver).toHaveBeenCalledTimes(1);
    });

    it('calls metricObserver with "5xx" when error.status is greater than 500', () => {
        const metricObserver = jest.fn();
        const error = { status: 599 };

        observeApiError(error, metricObserver);
        expect(metricObserver).toHaveBeenCalledWith('5xx');
        expect(metricObserver).toHaveBeenCalledTimes(1);
    });

    it('calls metricObserver with "4xx" when error.status is 400', () => {
        const metricObserver = jest.fn();
        const error = { status: 400 };

        observeApiError(error, metricObserver);
        expect(metricObserver).toHaveBeenCalledWith('4xx');
        expect(metricObserver).toHaveBeenCalledTimes(1);
    });

    it('calls metricObserver with "4xx" when error.status is 404', () => {
        const metricObserver = jest.fn();
        const error = { status: 404 };

        observeApiError(error, metricObserver);
        expect(metricObserver).toHaveBeenCalledWith('4xx');
        expect(metricObserver).toHaveBeenCalledTimes(1);
    });

    it('calls metricObserver with "4xx" when error.status is 499', () => {
        const metricObserver = jest.fn();
        const error = { status: 499 };

        observeApiError(error, metricObserver);
        expect(metricObserver).toHaveBeenCalledWith('4xx');
        expect(metricObserver).toHaveBeenCalledTimes(1);
    });

    it('calls metricObserver with "failure" when error.status is less than 400', () => {
        const metricObserver = jest.fn();
        const error = { status: 399 };

        observeApiError(error, metricObserver);
        expect(metricObserver).toHaveBeenCalledWith('failure');
        expect(metricObserver).toHaveBeenCalledTimes(1);
    });

    it('calls metricObserver with "failure" when error.status is 200', () => {
        const metricObserver = jest.fn();
        const error = { status: 200 };

        observeApiError(error, metricObserver);
        expect(metricObserver).toHaveBeenCalledWith('failure');
        expect(metricObserver).toHaveBeenCalledTimes(1);
    });

    it('calls metricObserver with "failure" when error has no status property', () => {
        const metricObserver = jest.fn();
        const error = { message: 'Some error' };

        observeApiError(error, metricObserver);
        expect(metricObserver).toHaveBeenCalledWith('failure');
        expect(metricObserver).toHaveBeenCalledTimes(1);
    });

    it('calls metricObserver exactly once even with multiple calls', () => {
        const metricObserver = jest.fn();
        const error = { status: 500 };

        observeApiError(error, metricObserver);
        observeApiError(error, metricObserver);

        expect(metricObserver).toHaveBeenCalledTimes(2);
    });
});

