        const error = { status: 200 };

        observeApiError(error, metricObserver);
        expect(metricObserver).toHaveBeenCalledWith('failure');
        expect(metricObserver).toHaveBeenCalledTimes(1);
    });

    it('calls metricObserver with "failure" when error has no status property', () => {
        const metricObserver = jest.fn();
        const error = { message: 'Some error' };

        observeApiError(error, metricObserver);
        expect(metricObserver).toHaveBeenCalledWith('failure');
        expect(metricObserver).toHaveBeenCalledTimes(1);
    });

    it('calls metricObserver exactly once even with multiple calls', () => {
        const metricObserver = jest.fn();
        const error = { status: 500 };

        observeApiError(error, metricObserver);
        observeApiError(error, metricObserver);

        expect(metricObserver).toHaveBeenCalledTimes(2);
    });
});

export type MetricsApiStatusTypes = '4xx' | '5xx' | 'failure';

export function observeApiError(error: any, metricObserver: (status: MetricsApiStatusTypes) => void): void {
    // Check if error is falsy
    if (!error) {
        metricObserver('failure');
        return;
    }

    // Get the status from the error object
    const status = error.status;

    // If status doesn't exist or is not a number, treat as failure
    if (typeof status !== 'number') {
        metricObserver('failure');
        return;
    }

    // Check status codes
    if (status >= 500) {
        metricObserver('5xx');
    } else if (status >= 400) {
        metricObserver('4xx');
    } else {
        metricObserver('failure');
    }
}

